'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { SearchForm } from '@/components/ui/search-form'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select'
import type { DomainOption } from '@/features/word/types'

interface WordSearchFormProps {
    defaultKeyword?: string
    defaultDomainId?: number
    domains: DomainOption[]
}

export function WordSearchForm({ defaultKeyword, defaultDomainId, domains }: WordSearchFormProps) {
    const router = useRouter()
    const [keyword, setKeyword] = useState(defaultKeyword ?? '')
    const [domainId, setDomainId] = useState<string>(defaultDomainId ? String(defaultDomainId) : '')

    const handleSearch = () => {
        const params = new URLSearchParams()
        if (keyword) params.set('keyword', keyword)
        if (domainId) params.set('domainId', domainId)
        params.set('page', '0')
        router.push(`/word?${params.toString()}`)
    }

    const handleReset = () => {
        setKeyword('')
        setDomainId('')
        router.push('/word')
    }

    return (
        <SearchForm onSearch={handleSearch} onReset={handleReset}>
            <div className="flex flex-col gap-1 min-w-[260px]">
                <Label htmlFor="keyword">검색어</Label>
                <Input
                    id="keyword"
                    value={keyword}
                    onChange={(e) => setKeyword(e.target.value)}
                    placeholder="한글명, 영문명, 약어 검색"
                />
            </div>
            <div className="flex flex-col gap-1 min-w-[200px]">
                <Label htmlFor="domainId">도메인</Label>
                <Select value={domainId} onValueChange={setDomainId}>
                    <SelectTrigger id="domainId">
                        <SelectValue placeholder="전체" />
                    </SelectTrigger>
                    <SelectContent>
                        <SelectItem value="">전체</SelectItem>
                        {domains.map((d) => (
                            <SelectItem key={d.id} value={String(d.id)}>
                                {d.code} - {d.name}
                            </SelectItem>
                        ))}
                    </SelectContent>
                </Select>
            </div>
        </SearchForm>
    )
}

