'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { format } from 'date-fns'
import { toast } from 'sonner'
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { deleteWord } from '@/features/word/actions'
import type { WordItem, DomainOption } from '@/features/word/types'
import { WordForm } from './WordForm'

interface WordDetailPanelProps {
    word: WordItem | null
    open: boolean
    onOpenChange: (open: boolean) => void
    domains: DomainOption[]
}

export function WordDetailPanel({ word, open, onOpenChange, domains }: WordDetailPanelProps) {
    const router = useRouter()
    const [editOpen, setEditOpen] = useState(false)
    const [deleting, setDeleting] = useState(false)

    const handleDelete = async () => {
        if (!word) return
        if (!confirm(`"${word.wordKor}" 단어를 삭제하시겠습니까?`)) return

        setDeleting(true)
        try {
            const result = await deleteWord(word.id)
            if (!result.success) {
                toast.error(result.error ?? '삭제 중 오류가 발생했습니다')
                return
            }
            toast.success('단어가 삭제되었습니다')
            onOpenChange(false)
            router.refresh()
        } catch {
            toast.error('삭제 중 오류가 발생했습니다')
        } finally {
            setDeleting(false)
        }
    }

    if (!word) return null

    return (
        <>
            <Dialog open={open} onOpenChange={onOpenChange}>
                <DialogContent className="sm:max-w-[480px]">
                    <DialogHeader>
                        <DialogTitle>단어 상세</DialogTitle>
                    </DialogHeader>
                    <dl className="grid grid-cols-[120px_1fr] gap-x-4 gap-y-3 text-sm">
                        <dt className="font-medium text-slate-500">ID</dt>
                        <dd>{word.id}</dd>
                        <dt className="font-medium text-slate-500">한글명</dt>
                        <dd>{word.wordKor}</dd>
                        <dt className="font-medium text-slate-500">영문명</dt>
                        <dd>{word.wordEng}</dd>
                        <dt className="font-medium text-slate-500">약어</dt>
                        <dd>{word.wordAbbr ?? '-'}</dd>
                        <dt className="font-medium text-slate-500">도메인</dt>
                        <dd>{word.domain ? `${word.domain.code} - ${word.domain.name}` : '-'}</dd>
                        <dt className="font-medium text-slate-500">등록일</dt>
                        <dd>{format(new Date(word.createdAt), 'yyyy-MM-dd')}</dd>
                    </dl>
                    <div className="flex justify-end gap-2 pt-4">
                        <Button
                            variant="destructive"
                            onClick={handleDelete}
                            disabled={deleting}
                        >
                            {deleting ? '삭제 중...' : '삭제'}
                        </Button>
                        <Button variant="outline" onClick={() => setEditOpen(true)}>
                            수정
                        </Button>
                    </div>
                </DialogContent>
            </Dialog>

            <WordForm
                open={editOpen}
                onOpenChange={setEditOpen}
                word={word}
                domains={domains}
                onSuccess={() => onOpenChange(false)}
            />
        </>
    )
}

'use client'

