import { prisma } from '@/lib/prisma'
import { searchWords } from '@/features/word/queries'
import { wordSearchSchema } from '@/features/word/schema'
import { PageHeader } from '@/components/ui/page-header'
import { WordSearchForm } from '@/features/word/components/WordSearchForm'
import { WordTable } from '@/features/word/components/WordTable'

export default async function WordPage({
    searchParams,
}: {
    searchParams: Promise<Record<string, string>>
}) {
    const params = wordSearchSchema.parse(await searchParams)
    const [{ items, total }, domains] = await Promise.all([
        searchWords(params),
        prisma.domain.findMany({ select: { id: true, code: true, name: true }, orderBy: { code: 'asc' } }),
    ])

    return (
        <div>
            <PageHeader title="단어 관리" description={`총 ${total}건`} />
            <WordSearchForm
                defaultKeyword={params.keyword}
                defaultDomainId={params.domainId}
                domains={domains}
            />
            <WordTable items={items} domains={domains} />
        </div>
    )
}

